        return isinstance(x, _number) and not isinstance(x, bool)

    try:
        if not isinstance(expression, str):
            return 'Error!'

        # Parse to AST in eval mode (single expression)
        parsed = ast.parse(expression, mode='eval')

        def _eval(node):
            if isinstance(node, ast.BinOp):
